detailed_optimizations.code_changes:
将当前 for(k) for(j) 更新改为对每个 (i,j) 先取局部累加器，再沿 k 做点积：
```cpp
for (int i = 0; i < n; ++i) {
  for (int j = 0; j <= i; ++j) {
    DATA_TYPE sum = beta * C[i][j];
    for (int k = 0; k < m; ++k)
      sum += alpha * A[i][k] * A[j][k];
    C[i][j] = sum;
  }
}
```
这样 C[i][j] 只读一次写一次，避免每个 k 都进行 RMW。若编译器支持，可进一步写成 `sum = fma(alpha * A[i][k], A[j][k], sum);`。

为 A/C 指针提供别名与对齐信息，并对 k 循环加 SIMD pragma。例如将 kernel 改写为扁平指针形式：
```cpp
void kernel_syrk_opt(int n, int m, DATA_TYPE alpha, DATA_TYPE beta,
                     DATA_TYPE* __restrict__ C,
                     const DATA_TYPE* __restrict__ A) {
  for (int i = 0; i < n; ++i) {
    for (int j = 0; j <= i; ++j) {
      DATA_TYPE sum = beta * C[i*n + j];
      const DATA_TYPE* __restrict__ Ai = &A[i*m];
      const DATA_TYPE* __restrict__ Aj = &A[j*m];
      #pragma omp simd reduction(+:sum)
      for (int k = 0; k < m; ++k)
        sum += alpha * Ai[k] * Aj[k];
      C[i*n + j] = sum;
    }
  }
}
```
同时编译时启用 `-O3 -march=native -ffast-math`（若数值允许）。

新增一次性预处理 `At[k][i] = A[i][k]`，然后计算时使用连续访问：
```cpp
for (int i = 0; i < n; ++i)
  for (int k = 0; k < m; ++k)
    At[k*n + i] = A[i*m + k];

for (int i = 0; i < n; ++i) {
  for (int j = 0; j <= i; ++j) {
    DATA_TYPE sum = beta * C[i*n + j];
    #pragma omp simd reduction(+:sum)
    for (int k = 0; k < m; ++k)
      sum += alpha * At[k*n + i] * At[k*n + j];
    C[i*n + j] = sum;
  }
}
```
若只运行一次 kernel，转置成本需与收益权衡；若多次调用同一 A，则收益明显。

采用块算法，对 C 的下三角块进行更新，典型块大小如 Bi=Bj=32~128, Bk=64~256，伪代码：
```cpp
for (int ii = 0; ii < n; ii += Bi)
  for (int jj = 0; jj <= ii; jj += Bj) {
    scale C block once by beta;
    for (int kk = 0; kk < m; kk += Bk) {
      pack A[ii:ii+Bi, kk:kk+Bk];
      pack A[jj:jj+Bj, kk:kk+Bk];
      micro-kernel update C block;
    }
  }
```
块内使用寄存器微核（如 4x4/8x6）累加，最后一次性写回 C。若不想手写微核，至少做 cache blocking 并在块级并行。

由于每个 C[i][j] 独立，可直接并行外层 i，负载不均时用 schedule(dynamic/guided) 或块级任务：
```cpp
#pragma omp parallel for schedule(guided)
for (int i = 0; i < n; ++i) {
  for (int j = 0; j <= i; ++j) {
    DATA_TYPE sum = beta * C[i*n + j];
    const DATA_TYPE* Ai = &A[i*m];
    const DATA_TYPE* Aj = &A[j*m];
    #pragma omp simd reduction(+:sum)
    for (int k = 0; k < m; ++k)
      sum += alpha * Ai[k] * Aj[k];
    C[i*n + j] = sum;
  }
}
```
更优方案是对三角块做 `collapse(2)` 风格任务化，仅遍历 `jj<=ii` 的块。

将内层从 for(k) for(j<=i) 改为 for(j<=i) for(k)，或更优地改写为按 (i,j) 计算点积：
for (i = 0; i < n; ++i) {
  for (j = 0; j <= i; ++j) {
    DATA_TYPE cij = beta * C[i][j];
    for (k = 0; k < m; ++k) {
      cij += alpha * A[j][k] * B[i][k] + alpha * B[j][k] * A[i][k];
    }
    C[i][j] = cij;
  }
}
这样 A[i][k], B[i][k], A[j][k], B[j][k] 都沿 k 连续访问，C[i][j] 仅一次读写，消除当前版本对 C 的反复读改写。

对 i/j 维做块化，仅处理下三角块；对 k 维做 panel blocking。示意：
for (ii = 0; ii < n; ii += Ti)
  for (jj = 0; jj <= ii; jj += Tj)
    for (kk = 0; kk < m; kk += Tk)
      for (i = ii; i < min(ii+Ti,n); ++i)
        for (j = jj; j < min(jj+Tj,i+1); ++j) {
          DATA_TYPE cij = (kk==0 ? beta*C[i][j] : C[i][j]);
          #pragma omp simd reduction(+:cij)
          for (k = kk; k < min(kk+Tk,m); ++k)
            cij += alpha*A[j][k]*B[i][k] + alpha*B[j][k]*A[i][k];
          C[i][j] = cij;
        }
推荐起始块大小：Tk=64~256，Ti/Tj=16~64，需按 L1/L2 容量调优。

将数组参数改为 restrict 指针或确保编译器知道无别名；对 A/B/C 做对齐分配；在 k 内层加 simd：
void kernel_syr2k(...,
  DATA_TYPE (* __restrict C)[N],
  DATA_TYPE (* __restrict A)[M],
  DATA_TYPE (* __restrict B)[M])
{
  ...
  for (i = 0; i < n; ++i)
    for (j = 0; j <= i; ++j) {
      DATA_TYPE cij = beta * C[i][j];
      #pragma omp simd aligned(A,B:64) reduction(+:cij)
      for (k = 0; k < m; ++k)
        cij += alpha*A[j][k]*B[i][k] + alpha*B[j][k]*A[i][k];
      C[i][j] = cij;
    }
}
编译选项建议：-O3 -march=native -ffast-math（若允许）-fopenmp-simd。

若必须保留某些循环结构，可预先构造 AT[k][i]=A[i][k], BT[k][i]=B[i][k]，使原先跨行访问变为连续访问；或在块内对 A/B 做 packing 到连续缓冲区。示意：
for (i=0;i<n;++i)
  for (k=0;k<m;++k) { AT[k][i]=A[i][k]; BT[k][i]=B[i][k]; }
随后使用按 k 连续的布局进行块乘更新。对于多次调用同一 A/B 的场景，转置成本更容易摊销。

由于每个 C[i][j] 独立，可并行外层 i 或块循环：
#pragma omp parallel for schedule(static)
for (i = 0; i < n; ++i) {
  for (j = 0; j <= i; ++j) {
    DATA_TYPE cij = beta * C[i][j];
    #pragma omp simd reduction(+:cij)
    for (k = 0; k < m; ++k)
      cij += alpha*A[j][k]*B[i][k] + alpha*B[j][k]*A[i][k];
    C[i][j] = cij;
  }
}
若采用分块，则并行 ii 块更利于负载均衡与 NUMA 首次接触策略。

将内层从 `for p { sum[p]=0; for s sum[p]+=A[r][q][s]*C4[s][p]; }` 改为 `for p sum[p]=0; for s { DATA_TYPE a = A[r][q][s]; for p sum[p] += a * C4[s][p]; }`。示例：
```cpp
for (r = 0; r < nr; r++)
  for (q = 0; q < nq; q++) {
    for (p = 0; p < np; p++) sum[p] = 0;
    for (s = 0; s < np; s++) {
      DATA_TYPE a = A[r][q][s];
      for (p = 0; p < np; p++)
        sum[p] += a * C4[s][p];
    }
    for (p = 0; p < np; p++)
      A[r][q][p] = sum[p];
  }
```
这一步是最关键的结构性优化。

在交换循环后，让最内层 p 成为连续内存访问并显式提示编译器向量化。可引入局部指针：
```cpp
void kernel_doitgen(...,
  DATA_TYPE (* __restrict A)[NQ][NP],
  DATA_TYPE (* __restrict C4)[NP],
  DATA_TYPE * __restrict sum)
{
  ...
  for (r = 0; r < nr; r++)
    for (q = 0; q < nq; q++) {
      DATA_TYPE* __restrict sumv = sum;
      for (p = 0; p < np; p++) sumv[p] = 0;
      for (s = 0; s < np; s++) {
        DATA_TYPE a = A[r][q][s];
        DATA_TYPE* __restrict c4row = &C4[s][0];
        #pragma omp simd aligned(sumv, c4row:64)
        for (p = 0; p < np; p++)
          sumv[p] += a * c4row[p];
      }
      #pragma omp simd aligned(sumv:64)
      for (p = 0; p < np; p++)
        A[r][q][p] = sumv[p];
    }
}
```
若编译器支持，可加 `-O3 -march=native -ffast-math`。

当 np 较大时，将 p 分块，例如 BP=32/64，使一个块的 sum 保持在寄存器/L1 中：
```cpp
const int BP = 64;
for (r = 0; r < nr; r++)
  for (q = 0; q < nq; q++)
    for (int pb = 0; pb < np; pb += BP) {
      int pend = (pb + BP < np) ? pb + BP : np;
      for (p = pb; p < pend; p++) sum[p] = 0;
      for (s = 0; s < np; s++) {
        DATA_TYPE a = A[r][q][s];
        #pragma omp simd
        for (p = pb; p < pend; p++)
          sum[p] += a * C4[s][p];
      }
      for (p = pb; p < pend; p++)
        A[r][q][p] = sum[p];
    }
```
进一步可手工展开 p 循环 4/8 路。

不同 (r,q) 对之间完全独立，但原代码中的 `sum` 是共享临时数组，必须私有化。推荐每线程私有局部缓冲：
```cpp
#pragma omp parallel for collapse(2) private(p,s)
for (r = 0; r < nr; r++)
  for (q = 0; q < nq; q++) {
    DATA_TYPE local_sum[NP];
    for (p = 0; p < np; p++) local_sum[p] = 0;
    for (s = 0; s < np; s++) {
      DATA_TYPE a = A[r][q][s];
      #pragma omp simd
      for (p = 0; p < np; p++)
        local_sum[p] += a * C4[s][p];
    }
    for (p = 0; p < np; p++)
      A[r][q][p] = local_sum[p];
  }
```
若 NP 不是编译期常量，可用 `std::vector<DATA_TYPE> local_sum(np);` 或线程私有分配。

若允许额外内存，可为 A 的输出使用独立数组 `Aout`，避免 `sum -> A` 的单独 copy-back 成为显式阶段，并便于 BLAS/GPU 实现：
```cpp
for (r = 0; r < nr; r++)
  for (q = 0; q < nq; q++) {
    for (p = 0; p < np; p++) Aout[r][q][p] = 0;
    for (s = 0; s < np; s++) {
      DATA_TYPE a = A[r][q][s];
      #pragma omp simd
      for (p = 0; p < np; p++)
        Aout[r][q][p] += a * C4[s][p];
    }
  }
swap(A, Aout);
```
若必须原地，可保留 local_sum 后一次写回；该阶段已较轻，不建议过度优化。

初始化不是主瓶颈，但可用 OpenMP collapse：
```cpp
#pragma omp parallel for collapse(3)
for (i = 0; i < nr; i++)
  for (j = 0; j < nq; j++)
    for (k = 0; k < np; k++)
      A[i][j][k] = (DATA_TYPE)((i*j + k)%np) / np;

#pragma omp parallel for collapse(2)
for (i = 0; i < np; i++)
  for (j = 0; j < np; j++)
    C4[i][j] = (DATA_TYPE)(i*j % np) / np;
```
仅在计时包含初始化时有意义。
